class Matrix:
    def __init__(self, rows): self.rows = rows
    def __matmul__(self, o):
        return Matrix([[sum(self.rows[i][k]*o.rows[k][j] for k in range(len(o.rows)))
                        for j in range(len(o.rows[0]))] for i in range(len(self.rows))])
    def T(self):
        return Matrix([list(c) for c in zip(*self.rows)])

A=Matrix([[1,2],[3,4]]); B=Matrix([[5,6],[7,8]])
lhs=(A@B).T().rows
rhs=(B.T()@A.T()).rows
print(lhs == rhs)   # True
```

`(AB)·µÄ = B·µÄA·µÄ` (note the reversed order) is used constantly when deriving backprop ‚Äî the gradient w.r.t. an input involves the transpose of the weight matrix.
